import { CommonModule } from '@angular/common';
import { Component, Input, OnChanges, OnInit, SimpleChanges } from '@angular/core';
import { TranslateModule, TranslateService } from '@ngx-translate/core';

export interface FNLabelProps {
  fieldType: 'FNLabel';
  name: string;
  label: string;
  className?: string;
  variant?: string;
  statusLabel?: string;
  validators?: any[];
  disabled?: boolean;
  hideOptional?: boolean;
}

@Component({
  selector: 'fn-label',
  standalone: true,
  imports: [CommonModule, TranslateModule],
  template: `
    @if (
      (label !== undefined && label !== null && label !== '') ||
      (field?.label !== undefined && field?.label !== null && field?.label !== '')
    ) {
      <label
        [for]="for || label"
        [ngClass]="ngClass"
        [class]="
          'fn-label !whitespace-normal ' +
          (statusLabel || field?.statusLabel
            ? statusLabel || field?.statusLabel
            : field?.variant || variant || '') +
          ' ' +
          (class || className || field?.className || '')
        "
        [style.color]="color || null"
      >
        {{ getTranslatedLabel(label || field?.label || '') }}
        @if (!required && !hideOptional && !field?.hideOptional) {
          <span>&nbsp;(Optional)</span>
        }
      </label>
    }
  `,
  styleUrls: ['./fn-label.component.scss'],
})
export class FNLabel implements OnInit, OnChanges {
  // 🧩 Inputs
  @Input() field?: FNLabelProps;
  @Input() label: string = '';
  @Input() required: boolean = true;
  @Input() className: string = '';
  @Input() class?: string = '';
  @Input() for: string = '';
  @Input() color: string = ''; // accepts hex, rgb, var(--token), or Tailwind class
  @Input() variant:
    | 'h1'
    | 'h1Bold'
    | 'h2'
    | 'h2Bold'
    | 'h3'
    | 'h3Bold'
    | 'p1'
    | 'p1Bold'
    | 'p2'
    | 'p2Bold'
    | 'p3'
    | 'p3Bold'
    | 'p4'
    | 'p4Bold'
    | 'interactionLarge'
    | 'interactionLargeBold'
    | 'interactionMedium'
    | 'interactionMediumBold'
    | 'interactionSmall'
    | 'interactionSmallBold'
    | 'avatarLabel' = 'p1';
  @Input() statusLabel?:
    | 'Standard'
    | 'Success'
    | 'Hot'
    | 'Warning'
    | 'Disabled'
    | 'RHBPremierBanking';
  @Input() ngClass: any = {};
  @Input() hideOptional: boolean = false;

  constructor(private readonly translate: TranslateService) {}

  ngOnInit(): void {
    this.initialize();
    if (this.label !== undefined && this.label !== null && this.label !== '') {
      if (Array.isArray(this.label)) {
        this.label = this.label.toString().split(',').join(', ');
      } else if (typeof this.label === 'string' || typeof this.label === 'number') {
        this.label = this.label.toString();
      } else {
        this.label = '';
      }
    }
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['required'] || changes['label']) {
      this.initialize();
    }
  }

  getEndSymbol(label: string): string {
    return label.toString().includes('required') && label.toString().includes('FNFieldMessage')
      ? '.'
      : '';
  }

  getTranslatedLabel(label: string): string {
    if (label === undefined || label === null || label === '') return ''; // handle undefined/null/empty upfront
    try {
      const labelStr = label.toString();
      return `${labelStr
        .split('::')
        .map((part) => part.trim())
        .filter((part) => !!part) // 🔹 skip empty parts
        .map((part) => this.translate.instant(part))
        .join(' ')}${this.getEndSymbol(labelStr)}`;
    } catch (e) {
      console.error('Error translating label:', label, e);
      return '';
    }
  }

  private initialize(): void {
    // reserved for initialization logic if needed later
  }
}
